"use client";
import { useEnvironmentContext } from "../environment/use-environment-context.js";
import { useCallback, useSyncExternalStore } from "react";
import { isFocusVisible, trackFocusVisible } from "@zag-js/focus-visible";
//#region src/providers/interaction/use-focus-visible.ts
function useFocusVisible(props = {}) {
	const { isTextInput, autoFocus } = props;
	const { getRootNode } = useEnvironmentContext();
	return useSyncExternalStore(useCallback((onStoreChange) => trackFocusVisible({
		root: getRootNode(),
		isTextInput,
		autoFocus,
		onChange: onStoreChange
	}), [
		getRootNode,
		isTextInput,
		autoFocus
	]), useCallback(() => autoFocus || isFocusVisible(), [autoFocus]), () => false);
}
//#endregion
export { useFocusVisible };
